import{_ as a,o,c as t,ag as r}from"./chunks/framework.BZohXCq9.js";const m=JSON.parse('{"title":"Usage","description":"Learn how bamdra-openclaw-memory is used in real OpenClaw workflows, including implicit continuity and explicit tool control.","frontmatter":{"title":"Usage","description":"Learn how bamdra-openclaw-memory is used in real OpenClaw workflows, including implicit continuity and explicit tool control."},"headers":[],"relativePath":"guide/usage.md","filePath":"guide/usage.md","lastUpdated":null}'),i={name:"guide/usage.md"};function n(l,e,s,c,d,h){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h1><h2 id="how-the-product-is-meant-to-be-used" tabindex="-1">How the product is meant to be used <a class="header-anchor" href="#how-the-product-is-meant-to-be-used" aria-label="Permalink to &quot;How the product is meant to be used&quot;">​</a></h2><p><code>bamdra-openclaw-memory</code> is designed to improve normal conversation first. In most sessions, the best experience is invisible continuity: the assistant quietly recovers the relevant branch, remembers durable facts, and avoids asking the user to repeat stable information.</p><h2 id="two-usage-modes" tabindex="-1">Two usage modes <a class="header-anchor" href="#two-usage-modes" aria-label="Permalink to &quot;Two usage modes&quot;">​</a></h2><h3 id="_1-implicit-continuity" tabindex="-1">1. Implicit continuity <a class="header-anchor" href="#_1-implicit-continuity" aria-label="Permalink to &quot;1. Implicit continuity&quot;">​</a></h3><p>This is the default experience. The user simply continues working in OpenClaw, while the memory layer:</p><ul><li>keeps earlier branches recoverable</li><li>assembles compact context for the active thread</li><li>reuses durable facts when they become relevant</li></ul><h3 id="_2-explicit-operator-control" tabindex="-1">2. Explicit operator control <a class="header-anchor" href="#_2-explicit-operator-control" aria-label="Permalink to &quot;2. Explicit operator control&quot;">​</a></h3><p>When a workflow becomes more complex, operators can directly use memory tools:</p><ul><li><code>memory_list_topics</code></li><li><code>memory_switch_topic</code></li><li><code>memory_save_fact</code></li><li><code>memory_compact_topic</code></li><li><code>memory_search</code></li></ul><h2 id="typical-usage-flow" tabindex="-1">Typical usage flow <a class="header-anchor" href="#typical-usage-flow" aria-label="Permalink to &quot;Typical usage flow&quot;">​</a></h2><h3 id="during-normal-work" tabindex="-1">During normal work <a class="header-anchor" href="#during-normal-work" aria-label="Permalink to &quot;During normal work&quot;">​</a></h3><p>The user moves between planning, execution, and follow-up. The memory layer should preserve the important branch without turning the conversation into a visible debugging process.</p><h3 id="when-a-fact-should-be-preserved" tabindex="-1">When a fact should be preserved <a class="header-anchor" href="#when-a-fact-should-be-preserved" aria-label="Permalink to &quot;When a fact should be preserved&quot;">​</a></h3><p>Use <code>memory_save_fact</code> for preferences, environment paths, project constraints, decisions, and other stable information that should remain useful later.</p><h3 id="when-the-team-wants-stronger-control" tabindex="-1">When the team wants stronger control <a class="header-anchor" href="#when-the-team-wants-stronger-control" aria-label="Permalink to &quot;When the team wants stronger control&quot;">​</a></h3><p>Use <code>memory_list_topics</code> and <code>memory_switch_topic</code> when a specific branch should be resumed or isolated deliberately.</p><h3 id="when-a-branch-grows-long" tabindex="-1">When a branch grows long <a class="header-anchor" href="#when-a-branch-grows-long" aria-label="Permalink to &quot;When a branch grows long&quot;">​</a></h3><p>Use <code>memory_compact_topic</code> to refresh summaries so later recovery remains accurate.</p><h2 id="daily-operator-guidance" tabindex="-1">Daily operator guidance <a class="header-anchor" href="#daily-operator-guidance" aria-label="Permalink to &quot;Daily operator guidance&quot;">​</a></h2><ul><li>let implicit recovery handle ordinary continuity</li><li>save only durable, reusable facts</li><li>search memory before asking the user to restate stable information</li><li>keep memory behavior useful, not noisy</li></ul>',21)])])}const p=a(i,[["render",n]]);export{m as __pageData,p as default};
